<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***APIuntukManajemenStatusPenugasan*PS,Plt,Pjs,Plh,Pj*/require_once'../core/config.php';require_once'auth_helper.php';classPenugasanManager{private$db;private$auth;publicfunction__construct(){$this->db=newmysqli(DB_HOST,DB_USER,DB_PASS,DB_NAME);$this->auth=APIAuth::getInstance();}/***Getalljabatanwithpenugasanstatus*/publicfunctiongetJabatanPenugasan(){$query="SELECTj.id,j.nama_jabatan,j.status_penugasan,j.alasan_penugasan,j.tanggal_mulai_penugasan,j.tanggal_selesai_penugasan,u.nama_unsur,COUNT(p.id)aspersonil_countFROMjabatanjLEFTJOINunsuruONj.id_unsur=u.idLEFTJOINpersonilpONj.id=p.id_jabatanGROUPBYj.id,j.nama_jabatan,j.status_penugasan,j.alasan_penugasan,j.tanggal_mulai_penugasan,j.tanggal_selesai_penugasan,u.nama_unsurORDERBYu.urutan,j.nama_jabatan";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data'\1\'=>\2,'nama_jabatan'=>$row['nama_jabatan'],'unsur'=>$row['nama_unsur'],'status_penugasan'=>$row['status_penugasan']?:'definitif','alasan_penugasan'=>$row['alasan_penugasan'],'tanggal_mulai_penugasan'=>$row['tanggal_mulai_penugasan'],'tanggal_selesai_penugasan'=>$row['tanggal_selesai_penugasan'],'personil_count'=>$row['personil_count'],'status'=>$this->getPenugasanStatus($row)];}return$data;}/***Updatestatuspenugasanjabatan*/publicfunctionupdateStatusPenugasan($jabatan_id,$status_penugasan,$alasan,$tanggal_mulai,$tanggal_selesai){/Validatestatus$valid_statuses=['definitif','ps','plt','pjs','plh','pj'];if(!in_array($status_penugasan,$valid_statuses)){thrownewException("Invalidstatuspenugasan");}/Validatejabatan$jabatan=$this->getJabatanById($jabatan_id);if(!$jabatan){thrownewException("Jabatannotfound");}/Validatestatusrules$this->validateStatusRules($jabatan,$status_penugasan);/Updatejabatan$query="UPDATEjabatanSETstatus_penugasan=?,alasan_penugasan=?,tanggal_mulai_penugasan=?,tanggal_selesai_penugasan=?WHEREid=?";$stmt=$this->db->prepare($query);$stmt->bind_param("ssssi",$status_penugasan,$alasan,$tanggal_mulai,$tanggal_selesai,$jabatan_id);$stmt->execute();/Updatepersonilassignmentifneeded$this->updatePersonilPenugasan($jabatan_id,$status_penugasan,$alasan,$tanggal_mulai,$tanggal_selesai);returntrue;}/***Getpenugasanstatistics*/publicfunctiongetPenugasanStats(){$query="SELECTstatus_penugasan,COUNT(*)astotal,ROUND(COUNT(*)*100.0/(SELECTCOUNT(*)FROMjabatan),2)aspercentageFROMjabatanGROUPBYstatus_penugasanORDERBYtotalDESC";$result=$this->db->query($query);$stats=[];while($row=$result->fetch_assoc()){$stats'\1\'=>\2?:'definitif','total'=>$row['total'],'percentage'=>$row['percentage']];}return$stats;}/***Getexpiredpenugasan*/publicfunctiongetExpiredPenugasan(){$query="SELECTj.id,j.nama_jabatan,j.status_penugasan,j.tanggal_selesai_penugasan,p.namaaspersonil_nama,DATEDIFF(CURDATE(),j.tanggal_selesai_penugasan)asdays_expiredFROMjabatanjLEFTJOINpersonilpONj.id=p.id_jabatanWHEREj.status_penugasan!='definitif'ANDj.tanggal_selesai_penugasan<CURDATE()ORDERBYdays_expiredDESC";$result=$this->db->query($query);$expired=[];while($row=$result->fetch_assoc()){$expired[]=$row;}return$expired;}/***Validatestatusrules*/privatefunctionvalidateStatusRules($jabatan,$status_penugasan){/PShanyauntuklevelEselonIIIkeatasif($status_penugasan==='ps'){if(strpos($jabatan['nama_jabatan'],'KANIT')!==false||strpos($jabatan['nama_jabatan'],'BINTARA')!==false){thrownewException("PStidakbolehuntukjabatanlevelKANITkebawah");}}/Pjshanyauntukleveltinggiif($status_penugasan==='pjs'){if(strpos($jabatan['nama_jabatan'],'KABAG')===false&&strpos($jabatan['nama_jabatan'],'KASAT')===false&&strpos($jabatan['nama_jabatan'],'KAPOLRES')===false){thrownewException("PjshanyauntukjabatanlevelKABAGkeatas");}}/CheckPSpercentageif($status_penugasan==='ps'){$ps_count=$this->getPSCount();$total_jabatan=$this->getTotalJabatan();$ps_percentage=($ps_count/$total_jabatan)*100;if($ps_percentage>15){thrownewException("PStidakbolehlebihdari15%daritotaljabatan");}}}/***Getpenugasanstatus*/privatefunctiongetPenugasanStatus($jabatan){if($jabatan'\1\'=>=='definitif'){return'active';}if(!$jabatan['tanggal_selesai_penugasan']){return'active';}$today=newDateTime();$end_date=newDateTime($jabatan['tanggal_selesai_penugasan']);if($end_date<$today){return'expired';}$diff=$today->diff($end_date);if($diff->days<=30){return'expiring_soon';}return'active';}/***Helpermethods*/privatefunctiongetJabatanById($id){$query="SELECT*FROMjabatanWHEREid=?";$stmt=$this->db->prepare($query);$stmt->bind_param("i",$id);$stmt->execute();return$stmt->get_result()->fetch_assoc();}privatefunctiongetPSCount(){$query="SELECTCOUNT(*)ascountFROMjabatanWHEREstatus_penugasan='ps'";$result=$this->db->query($query);return$result->fetch_assoc()['count'];}privatefunctiongetTotalJabatan(){$query="SELECTCOUNT(*)ascountFROMjabatan";$result=$this->db->query($query);return$result->fetch_assoc()['count'];}privatefunctionupdatePersonilPenugasan($jabatan_id,$status_penugasan,$alasan,$tanggal_mulai,$tanggal_selesai){$query="UPDATEpersonilSETstatus_penugasan=?,alasan_penugasan=?,tanggal_mulai_penugasan=?,tanggal_selesai_penugasan=?WHEREid_jabatan=?";$stmt=$this->db->prepare($query);$stmt->bind_param("ssssi",$status_penugasan,$alasan,$tanggal_mulai,$tanggal_selesai,$jabatan_id);$stmt->execute();}}/APIHandlertry{$penugasan=newPenugasanManager();$action=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2{case'get_penugasan_list':$penugasan->auth->requireAuth();$data=$penugasan->getJabatanPenugasan();echojson_encode('\1\'=>\2);break;case'update_status_penugasan':$penugasan->auth->requireAuth();$jabatan_id=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2,'status_penugasan',FILTER_DEFAULT)??'';$alasan=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2,'tanggal_mulai',FILTER_DEFAULT)??null;$tanggal_selesai=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2;echojson_encode('\1\'=>\2);break;case'get_penugasan_stats':$penugasan->auth->requireAuth();$stats=$penugasan->getPenugasanStats();echojson_encode('\1\'=>\2);break;case'get_expired_penugasan':$penugasan->auth->requireAuth();$expired=$penugasan->getExpiredPenugasan();echojson_encode('\1\'=>\2);break;default:header('HTTP/1.0400BadRequest');echojson_encode('\1\'=>\2);}}catch(Exception$e){header('HTTP/1.0500InternalServerError');echojson_encode('\1\'=>\2);}?>
